/* ============================================================
   PRESET « ALBION ONLINE » v3 — Bloxd Terrain Editor
   Monde 1500 x 1000 — relief généré par le MOTEUR DU SITE.

   NOUVEAU v3 :
   - Nettoie les anciens presets Albion (fix erreur de quota)
   - Applique la carte IMMÉDIATEMENT (pas besoin de recharger)
   - Sauvegarde compacte : ~180 Ko au lieu de 3 Mo

   Installation :
   1. Ouvre l'application (index.html)
   2. F12 -> onglet Console
   3. Colle TOUT ce fichier, Entrée
   4. La carte se charge directement sous tes yeux !
   ============================================================ */
(function () {
    var M = {"cols":300,"rows":200,"step":5,"worldX":1500,"worldZ":1000,"bio":["","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","",""],"dl":["","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","",""],"ds":["","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","","",""]};

    var gen = window.generatorInstance;
    if (!gen) { alert("Ouvre d'abord l'application Bloxd Terrain Editor !"); return; }

    console.log('%c⏳ Génération du relief Albion avec le moteur du site...', 'color:#38bdf8');

    // --- Moteur de bruit du site (identique aux presets officiels) ---
    var SEED = 20260707;
    var noiseGen = new window.TerrainGenerator();
    noiseGen.initPermutationTable(SEED);
    var vn = function (x, z) { return noiseGen.valueNoise2D(x, z); };
    var smooth = function (t) { return t * t * (3 - 2 * t); };
    var B36 = '0123456789abcdefghijklmnopqrstuvwxyz';

    var SEA = 88, cols = M.cols, rows = M.rows, STEP = M.step;
    var biomeOf = { o: 'sand', s: 'sand', p: 'plain', f: 'forest', m: 'mountain', n: 'snow' };

    // --- 1. Hauteur par cellule : base biome + fbm du site + rampe côtière ---
    var hmap = [], isSea = [];
    for (var cz = 0; cz < rows; cz++) {
        hmap[cz] = []; isSea[cz] = [];
        var bioRow = M.bio[cz], dlRow = M.dl[cz], dsRow = M.ds[cz];
        for (var cx = 0; cx < cols; cx++) {
            var b = bioRow[cx];
            var wx = cx * STEP - M.worldX / 2, wz = cz * STEP - M.worldZ / 2;
            var h;
            if (b === 'o') {
                var ds = B36.indexOf(dsRow[cx]);
                h = 86 - Math.min(ds, 18) * 1.1 + (vn(wx * 0.02, wz * 0.02) - 0.5) * 3;
                if (h > SEA - 1) h = SEA - 1;
                isSea[cz][cx] = true;
            } else {
                var dl = B36.indexOf(dlRow[cx]);
                var t = smooth(Math.min(dl, 8) / 8);
                var n1 = vn(wx * 0.008, wz * 0.008);
                var n2 = vn(wx * 0.0184 + 19.7, wz * 0.0184 - 41.2);
                var ridge = 1 - Math.abs(2 * n2 - 1);
                var n3 = vn(wx * 0.0408, wz * 0.0408);
                if (b === 's')      h = 90 + t * 4  + (n1 - 0.5) * 6  + (n3 - 0.5) * 2;
                else if (b === 'p') h = 93 + t * 6  + (n1 - 0.5) * 10 + (n3 - 0.5) * 3;
                else if (b === 'f') h = 96 + t * 8  + (n1 - 0.5) * 12 + (n3 - 0.5) * 4;
                else if (b === 'm') h = 102 + t * 12 + (n1 - 0.5) * 16 + ridge * 26 + (n3 - 0.5) * 5;
                else                h = 112 + t * 14 + (n1 - 0.5) * 18 + ridge * 34 + (n3 - 0.5) * 5;
                var shore = smooth(Math.min(dl, 6) / 6);
                h = 89.5 + (h - 89.5) * (0.25 + 0.75 * shore);
                if (h < SEA + 1) h = SEA + 1;
                isSea[cz][cx] = false;
            }
            hmap[cz][cx] = h;
        }
    }

    // --- 2. Deux passes de lissage 3x3 (trait de côte figé) ---
    for (var pass = 0; pass < 2; pass++) {
        var nh = [];
        for (cz = 0; cz < rows; cz++) {
            nh[cz] = [];
            for (cx = 0; cx < cols; cx++) {
                var sum = 0, n = 0;
                for (var dz = -1; dz <= 1; dz++) {
                    for (var dx = -1; dx <= 1; dx++) {
                        var az = cz + dz, ax = cx + dx;
                        if (az < 0 || az >= rows || ax < 0 || ax >= cols) continue;
                        if (isSea[az][ax] !== isSea[cz][cx]) continue;
                        sum += hmap[az][ax]; n++;
                    }
                }
                nh[cz][cx] = sum / n;
            }
        }
        hmap = nh;
    }

    // --- 3. Édits ---
    var edits = {};
    for (cz = 0; cz < rows; cz++) {
        for (cx = 0; cx < cols; cx++) {
            var hh = Math.round(hmap[cz][cx]);
            if (isSea[cz][cx] && hh > SEA) hh = SEA;
            if (!isSea[cz][cx] && hh <= SEA) hh = SEA + 1;
            var wx2 = cx * STEP - M.worldX / 2, wz2 = cz * STEP - M.worldZ / 2;
            edits[wx2 + ',' + wz2] = { height: hh, biome: biomeOf[M.bio[cz][cx]], half: STEP / 2 };
        }
    }

    var config = {
        worldSizeX: M.worldX, worldSizeZ: M.worldZ,
        viewportMode: 'global', gridResolution: 256,
        seed: SEED, baseY: 70, seaLevel: SEA,
        minHeight: 60, maxHeight: 200,
        noiseScale: 0.008, terrainIntensity: 10, roughness: 0.5,
        showWater: true, defaultBiome: 'plain', pixelatedExport: false
    };
    var preset = {
        name: '🗡️ Albion Online v3 (relief naturel)',
        config: config,
        customEdits: edits
    };

    // --- 4. APPLICATION IMMÉDIATE (aucun localStorage requis !) ---
    gen.saveStateForUndo && gen.saveStateForUndo();
    gen.presets['custom_albion_v3'] = preset;
    Object.assign(gen.config, config);
    gen.customEdits = new Map();
    for (var k in edits) gen.customEdits.set(k, edits[k]);
    gen._editIndexDirty = true;
    gen.generateGrid(false);
    if (window.map2dInstance) window.map2dInstance.render();
    if (window.map3dInstance) window.map3dInstance.updateTerrain();
    if (window.uiManagerInstance) {
        window.uiManagerInstance.syncUIWithConfig && window.uiManagerInstance.syncUIWithConfig();
        window.uiManagerInstance.updateStatsBar && window.uiManagerInstance.updateStatsBar();
    }
    // Ajoute l'option au menu des presets pour la session
    var sel = document.getElementById('select-preset');
    if (sel && !sel.querySelector('option[value="custom_albion_v3"]')) {
        var opt = document.createElement('option');
        opt.value = 'custom_albion_v3';
        opt.textContent = '⭐ ' + preset.name;
        opt.selected = true;
        sel.appendChild(opt);
    }
    console.log('%c✓ Carte Albion v3 chargée et affichée !', 'color:#10b981;font-weight:bold');

    // --- 5. Persistance (fix quota) : purge des anciens Albion puis tentative ---
    try {
        var saved = JSON.parse(localStorage.getItem('bloxd_custom_presets') || '{}');
        // FIX QUOTA : supprime les anciennes versions volumineuses (v1 ~3 Mo !)
        for (var key in saved) {
            if (key.indexOf('albion') !== -1 || (saved[key].name || '').indexOf('Albion') !== -1) delete saved[key];
        }
        saved['custom_albion_v3'] = preset;
        localStorage.setItem('bloxd_custom_presets', JSON.stringify(saved));
        console.log('%c✓ Preset sauvegardé : il restera disponible après rechargement.', 'color:#10b981');
    } catch (e) {
        // Quota toujours dépassé : on garde les autres presets de l'utilisateur intacts
        console.warn('⚠️ Sauvegarde impossible (' + e.message + ').');
        console.warn('La carte est bien CHARGÉE pour cette session : exporte ton .bloxdschem maintenant,');
        console.warn('ou relance ce script après un rechargement de page.');
        console.warn('Pour libérer de la place : localStorage.removeItem("bloxd_custom_presets")');
    }
})();
